        p.right = b;
        g.left = c;

        // Verify intermediate subtrees are BST
        proof {
            assert(p.is_bst());
            assert(g.is_bst());
        }

        // Final assembly: X takes P and G
        x.left = Some(p);
        x.right = Some(g);

        // 4. Final verification of the result node X
        proof {
            let left_child = x.left.get_Some_0();
            let right_child = x.right.get_Some_0();

            // Verify the composition of the new views
            assert(left_child.view() =~= v_a.union(v_b).insert(p_val));
            assert(right_child.view() =~= v_c.union(v_d).insert(g_val));

            // Verify range for X's left child
