            // Verify range for X's right child
            assert(forall |v| #[trigger] right_child.view().contains(v) ==> v > x_val);

            // Final BST check
            assert(x.is_bst());

            // Check view identity
            assert(x.view() =~= g_view_orig);
        }

        x
    }
    // </code>

    #[verifier::external]
    fn main() {}
